import sys
sys.setrecursionlimit(200000)

def solve(nums):
    n = len(nums)
    if all(i == x for i, x in enumerate(nums)):
        return 0

    def find(x, parent):
        if parent[x] != x:
            parent[x] = find(parent[x], parent)
        return parent[x]

    def union(x, y, parent, rank):
        rx = find(x, parent)
        ry = find(y, parent)
        if rx == ry:
            return
        if rank[rx] < rank[ry]:
            parent[rx] = ry
        elif rank[rx] > rank[ry]:
            parent[ry] = rx
        else:
            parent[ry] = rx
            rank[rx] += 1

    max_k = 0
    for k in range(n-1, -1, -1):
        S = []
        in_s = [False] * (n + 1)
        for a in range(n):
            if (a & k) == k:
                S.append(a)
                in_s[a] = True

        if not S:
            for i in range(n):
                if nums[i] != i:
                    break
            else:
                return k
            continue

        max_bit = n.bit_length()
        all_bits = (1 << max_bit) - 1
        U0_mask = (all_bits ^ k)

        masks_in_s = set()
        mask_to_numbers = {}
        for a in S:
            mask = a & U0_mask
            masks_in_s.add(mask)
            if mask not in mask_to_numbers:
                mask_to_numbers[mask] = []
            mask_to_numbers[mask].append(a)

        M = sorted(list(masks_in_s))
        parent_uf = {}
        rank_uf = {}
        for m in M:
            parent_uf[m] = m
            rank_uf[m] = 0

        for mask1 in M:
            comp_mask = U0_mask & (~mask1)
            submask = comp_mask
            while submask:
                if submask in masks_in_s:
                    if find(mask1, parent_uf) != find(submask, parent_uf):
                        union(mask1, submask, parent_uf, rank_uf)
                submask = (submask - 1) & comp_mask
            if 0 in masks_in_s:
                if 0 != mask1 and 0 in masks_in_s:
                    if find(mask1, parent_uf) != find(0, parent_uf):
                        union(mask1, 0, parent_uf, rank_uf)

        root_component_map = {}
        comp_id = [-1] * (n + 1)
        comp_counter = 0
        for a in range(n):
            if not in_s[a]:
                comp_id[a] = comp_counter
                comp_counter += 1

        for m in M:
            root = find(m, parent_uf)
            if root not in root_component_map:
                root_component_map[root] = comp_counter
                comp_counter += 1

        for a in S:
            m = a & U0_mask
            root = find(m, parent_uf)
            comp_id[a] = root_component_map[root]

        valid = True
        for x in range(n):
            if comp_id[x] == comp_id[nums[x]]:
                continue
            valid = False
            break

        if valid:
            return k

    return 0
```

