class UnionFind:
    def __init__(self):
        self.parent = {}

    def make_set(self, x):
        if x not in self.parent:
            self.parent[x] = x

    def find(self, x):
        self.make_set(x)
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        rx = self.find(x)
        ry = self.find(y)
        if rx != ry:
            self.parent[ry] = rx

def solve(nums: list) -> int:
    n = len(nums)
    if n == 0:
        return 0
    if nums == sorted(nums):
        return 0

    max_val = n - 1
    if max_val == 0:
        bit_len = 1
    else:
        bit_len = max_val.bit_length()
    total_mask = (1 << bit_len) - 1

    def is_valid(k):
        for i in range(n):
            if nums[i] != i:
                if ((i & k) != k) or ((nums[i] & k) != k):
                    return False

        M_val = total_mask & (~k)
        set_S = [x for x in range(n) if (x & k) == k]

        if not set_S:
            for i in range(n):
                if nums[i] != i:
                    return False
            return True

        uf = UnionFind()
        for x in set_S:
            uf.make_set(x)

        rep_arr = [-1] * (1 << bit_len)

        for u in set_S:
            base = u & M_val
            rest = M_val & (~base)

            sm = rest
            while True:
                if rep_arr[sm] != -1:
                    v = rep_arr[sm]
                    uf.union(u, v)
                if sm == 0:
                    break
                sm = (sm - 1) & rest

            rep_arr[base] = u

        for i in range(n):
            if nums[i] != i:
                if uf.find(i) != uf.find(nums[i]):
                    return False
        return True

    candidate = 0
    for bit_index in range(bit_len - 1, -1, -1):
        k_new = candidate | (1 << bit_index)
        if is_valid(k_new):
            candidate = k_new

    return candidate
```

